insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('computer-science:1-6-1b-legislation:tf:fef3ef3b', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'tf', 'tf', 1, '{"question": "The Data Protection Act 2018 is the law that protects people''s personal data."}'::jsonb, '{"answer": true, "explain": "Correct — the DPA controls how organisations collect, store and use personal data and gives individuals rights over it."}'::jsonb),
('computer-science:1-6-1b-legislation:tf:b8304e37', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'tf', 'tf', 1, '{"question": "Copying and selling someone''s software without permission breaks the Data Protection Act."}'::jsonb, '{"answer": false, "explain": "It breaks the Copyright, Designs and Patents Act 1988, which protects original work such as software from being copied."}'::jsonb),
('computer-science:1-6-1b-legislation:tf:3e441bc9', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'tf', 'tf', 1, '{"question": "Under the Data Protection Act, an organisation can freely sell customers'' personal data to anyone it likes."}'::jsonb, '{"answer": false, "explain": "The DPA forbids sharing or selling personal data without the person''s consent — this would breach the Act."}'::jsonb),
('computer-science:1-6-1b-legislation:tf:ca1bfe91', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'tf', 'tf', 1, '{"question": "Spreading a virus that deletes files is an offence under the Computer Misuse Act."}'::jsonb, '{"answer": true, "explain": "Correct — this is unauthorised modification of data, one of the Computer Misuse Act''s offences."}'::jsonb),
('computer-science:1-6-1b-legislation:tf:f0dca738', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'tf', 'tf', 1, '{"question": "The Freedom of Information Act lets the public request information held by public authorities."}'::jsonb, '{"answer": true, "explain": "Correct — the FoI Act gives the public the right to request information from bodies such as councils and schools."}'::jsonb),
('computer-science:1-6-1b-legislation:tf:e35dbc04', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'tf', 'tf', 1, '{"question": "The Copyright, Designs and Patents Act protects computer systems from being hacked."}'::jsonb, '{"answer": false, "explain": "Protecting systems from hacking is the Computer Misuse Act. The CDPA protects original work such as software and music."}'::jsonb),
('computer-science:1-6-1b-legislation:tf:1e0f8877', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'tf', 'tf', 1, '{"question": "A logo is an original work that is protected by the Copyright, Designs and Patents Act."}'::jsonb, '{"answer": true, "explain": "Correct — a logo is intellectual property, so copying it without permission breaches the CDPA."}'::jsonb),
('computer-science:1-6-1b-legislation:learn:27720e5a', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'learn', 'mcq', 1, '{"readingTitle": "Why we need laws for computers", "reading": "<h4>Technology created new ways to cause harm</h4>\n<ul>\n<li>Computers made it possible to <strong>store huge amounts of personal data</strong>, <strong>break into systems</strong>, and <strong>copy other people''s work perfectly</strong> — so the law had to keep up.</li>\n<li>You need to know <strong>three key Acts</strong> for the exam, and what each one is <strong>for</strong>:</li>\n<li><strong>Data Protection Act 2018</strong> — protects people''s <strong>personal data</strong>.</li>\n<li><strong>Computer Misuse Act 1990</strong> — makes <strong>hacking</strong> and misuse of computers illegal.</li>\n<li><strong>Copyright, Designs and Patents Act 1988</strong> — protects people''s <strong>original work</strong> (intellectual property).</li>\n<li>A fourth, the <strong>Freedom of Information Act 2000</strong>, sometimes appears too. The key exam skill is picking the <strong>right law for a given situation</strong>.</li>\n</ul>", "question": "Why were new laws such as the Computer Misuse Act needed?", "options": ["Because computers were becoming so expensive that the government had to control exactly who was allowed to buy one", "Because computers created new ways to cause harm, such as hacking, that older laws did not clearly cover", "Because computers use a large amount of electricity and the law had to limit how much energy each one could use", "Because computers were making too many older jobs disappear and a law was needed to bring all of them back again"]}'::jsonb, '{"answer": 1, "explain": "Computers created new kinds of harm (hacking, data misuse, easy copying) that existing laws didn''t cover, so new legislation was introduced."}'::jsonb),
('computer-science:1-6-1b-legislation:learn:b0910313', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'learn', 'mcq', 1, '{"readingTitle": "Data Protection Act 2018 — what it is for", "reading": "<h4>Controlling how personal data is handled</h4>\n<ul>\n<li>The <strong>Data Protection Act 2018 (DPA)</strong> controls how organisations <strong>collect, store and use people''s personal data</strong> (information about identifiable living people).</li>\n<li>It gives people <strong>rights</strong> over their own data — for example the right to <strong>see</strong> what an organisation holds about them, and to have <strong>mistakes corrected</strong>.</li>\n<li>It applies whenever a business, school or club <strong>stores data about people</strong> — so it is the law that covers customer records, student records, and so on.</li>\n</ul>", "question": "What does the Data Protection Act 2018 mainly control?", "options": ["The maximum number of computers that any single organisation is legally allowed to own and use at one time", "How organisations collect, store and use people''s personal data, and the rights people have over it", "Whether it is legal for a person to copy and share a piece of software that somebody else has written", "The amount of electricity that a large company''s data centre is permitted to use over the course of a year"]}'::jsonb, '{"answer": 1, "explain": "The DPA controls how organisations handle personal data and gives individuals rights over their own data."}'::jsonb),
('computer-science:1-6-1b-legislation:learn:e1640bf5', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'learn', 'mcq', 1, '{"readingTitle": "Data Protection Act — what organisations must do", "reading": "<h4>The organisation''s responsibilities</h4>\n<ul>\n<li>Personal data must be <strong>kept secure</strong> from unauthorised access — for example using passwords, access rights, encryption and firewalls.</li>\n<li>Data must only be <strong>collected and used with consent</strong>, kept for the <strong>stated purpose</strong>, be <strong>accurate</strong>, and <strong>not kept for longer than needed</strong>.</li>\n<li>Organisations must <strong>not share or sell</strong> personal data without permission, and larger ones may need to appoint a <strong>data protection officer</strong> to make sure the rules are followed.</li>\n</ul>", "question": "Which of these is a requirement of the Data Protection Act 2018 for an organisation storing personal data?", "options": ["It must publish all of the personal data it holds on its public website so that anyone is able to check it", "It must keep the data secure and not share or sell it without the person''s consent", "It must delete every piece of personal data it holds at the end of each and every working day without fail", "It must store the personal data of as many people as it possibly can in order to grow the business quickly"]}'::jsonb, '{"answer": 1, "explain": "The DPA requires personal data to be kept secure and not shared or sold without consent — publishing it or selling it freely would breach the Act."}'::jsonb),
('computer-science:1-6-1b-legislation:learn:8dda27d6', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'learn', 'mcq', 1, '{"readingTitle": "Computer Misuse Act 1990 — what it is for", "reading": "<h4>Making hacking and misuse illegal</h4>\n<ul>\n<li>The <strong>Computer Misuse Act 1990 (CMA)</strong> makes it a crime to <strong>access or change a computer system without permission</strong> — in other words, it makes <strong>hacking</strong> illegal.</li>\n<li>It covers three main offences:</li>\n<li><strong>1. Unauthorised access</strong> to computer material (e.g. logging into someone''s account without permission).</li>\n<li><strong>2. Unauthorised access with intent</strong> to commit a further crime (e.g. hacking in to steal money or data).</li>\n<li><strong>3. Unauthorised modification</strong> of data (e.g. deleting or changing files, or spreading malware such as a virus).</li>\n</ul>", "question": "Which action would break the Computer Misuse Act 1990?", "options": ["A person taking a photograph on their own phone and then choosing to share it with a few of their friends", "A person logging into someone else''s email account without permission to read their private messages", "A company keeping a secure, encrypted backup of its own customers'' data on a separate storage device", "A student writing their own computer program from scratch and then running it on their own home computer"]}'::jsonb, '{"answer": 1, "explain": "Accessing someone else''s account without permission is unauthorised access — a clear breach of the Computer Misuse Act."}'::jsonb),
('computer-science:1-6-1b-legislation:learn:9a3f247b', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'learn', 'mcq', 1, '{"readingTitle": "Copyright, Designs and Patents Act 1988 — what it is for", "reading": "<h4>Protecting people''s original work</h4>\n<ul>\n<li>The <strong>Copyright, Designs and Patents Act 1988 (CDPA)</strong> protects <strong>intellectual property</strong> — a person''s or company''s <strong>original work</strong>.</li>\n<li>It covers things like <strong>software, music, films, images, writing and designs</strong>. The creator automatically owns the <strong>copyright</strong>.</li>\n<li>It is <strong>illegal to copy, use, share or sell</strong> someone''s copyrighted work <strong>without their permission</strong> — this includes <strong>software piracy</strong> (illegally copying programs) and using someone''s image or logo without permission.</li>\n</ul>", "question": "What does the Copyright, Designs and Patents Act 1988 protect?", "options": ["The amount of personal data that a large online company is allowed to collect about each of its customers", "People''s original work, such as software, music, images and writing, from being copied without permission", "Computer systems from being accessed or hacked into by someone who does not have the owner''s permission", "The right of any member of the public to request information that is held by a local council or a school"]}'::jsonb, '{"answer": 1, "explain": "The CDPA protects original work (intellectual property) such as software, music and images from being copied or used without permission."}'::jsonb),
('computer-science:1-6-1b-legislation:learn:5ae8ecda', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'learn', 'mcq', 1, '{"readingTitle": "Freedom of Information Act 2000", "reading": "<h4>The public''s right to request information</h4>\n<ul>\n<li>The <strong>Freedom of Information Act 2000 (FoI)</strong> gives members of the public the <strong>right to request information</strong> held by <strong>public authorities</strong> — such as councils, schools, hospitals and government departments.</li>\n<li>The authority must normally <strong>respond and provide the information</strong>, unless there is a good reason not to (for example if it would breach someone''s data protection or national security).</li>\n<li>It is about <strong>openness of public bodies</strong> — very different from the Data Protection Act, which protects <strong>personal</strong> data about individuals.</li>\n</ul>", "question": "What does the Freedom of Information Act 2000 allow?", "options": ["It allows absolutely any company to freely share and then go on to sell the personal data of its own customers to any other company", "It allows members of the public to request information held by public authorities such as councils and schools", "It allows a person to copy and reuse any piece of software as long as they do not try to sell it for a profit", "It allows the police to access any computer system they wish without needing to obtain any permission first"]}'::jsonb, '{"answer": 1, "explain": "The Freedom of Information Act lets the public request information held by public authorities — it is about openness of public bodies."}'::jsonb),
('computer-science:1-6-1b-legislation:learn:511dc617', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'learn', 'mcq', 1, '{"readingTitle": "Choosing the right law for a scenario", "reading": "<h4>The exam''s favourite question</h4>\n<p>You are very often given a situation and asked <strong>which law applies</strong>. Use these quick tests:</p>\n<ul>\n<li>Is it about <strong>personal data</strong> being mishandled, shared or leaked? → <strong>Data Protection Act 2018</strong>.</li>\n<li>Is it about <strong>accessing or changing a system without permission</strong> (hacking, malware)? → <strong>Computer Misuse Act 1990</strong>.</li>\n<li>Is it about <strong>copying someone''s work</strong> (software, image, music, logo) without permission? → <strong>Copyright, Designs and Patents Act 1988</strong>.</li>\n<li>Is it about <strong>asking a public body for information</strong>? → <strong>Freedom of Information Act 2000</strong>.</li>\n</ul>\n<p>Watch the trap: storing customer data is <strong>Data Protection</strong>, <strong>not</strong> Computer Misuse or Copyright — a very common mistake.</p>", "question": "A company shares its customers'' personal data with another company without the customers'' permission. Which law does this break?", "options": ["The Computer Misuse Act 1990, because sharing any kind of data always counts as misusing a computer system", "The Data Protection Act 2018, because it controls how personal data may be stored, used and shared", "The Copyright, Designs and Patents Act 1988, because the customer list was created by the company itself", "The Freedom of Information Act 2000, because the customers have a right to request their own information back"]}'::jsonb, '{"answer": 1, "explain": "Mishandling or sharing personal data without consent breaches the Data Protection Act 2018 — the law that governs personal data."}'::jsonb),
('computer-science:1-6-1b-legislation:misc:40df7419', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking that storing or losing customer data is covered by the Computer Misuse Act.</p><p><strong>✅ The correct idea:</strong> The <strong>Computer Misuse Act</strong> is about <strong>unauthorised access</strong> (hacking) and changing systems without permission. Handling <strong>personal data</strong> — storing it, keeping it secure, sharing it — is the <strong>Data Protection Act 2018</strong>. Mixing these two up is one of the most common exam errors.</p>", "question": "A company accidentally leaks its customers'' personal data. Which law has it most likely failed to follow?", "options": ["The Computer Misuse Act 1990, because a leak means someone must have hacked into the company''s systems", "The Data Protection Act 2018, because it requires personal data to be kept secure", "The Copyright, Designs and Patents Act 1988, because the customer list is the company''s own original work", "The Freedom of Information Act 2000, because the customers have a right to know that the leak has happened"]}'::jsonb, '{"answer": 1, "explain": "Failing to keep personal data secure is a Data Protection Act failing — not the Computer Misuse Act, which is about hacking."}'::jsonb),
('computer-science:1-6-1b-legislation:misc:989b176f', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Believing the Copyright Act protects computer systems from hackers.</p><p><strong>✅ The correct idea:</strong> The <strong>Copyright, Designs and Patents Act</strong> protects <strong>original work</strong> (software, music, images, writing) from being <strong>copied</strong>. Protecting <strong>systems</strong> from being <strong>hacked</strong> is the <strong>Computer Misuse Act</strong>. One is about copying work; the other is about breaking in.</p>", "question": "Which law is broken by illegally copying and distributing a piece of paid-for software?", "options": ["The Computer Misuse Act, because copying the software means gaining access to the company''s private systems", "The Copyright, Designs and Patents Act 1988, because the software is original work protected by copyright", "The Data Protection Act, because the software will contain some of the personal data of the people who made it", "The Freedom of Information Act, because customers have the right to a free copy of any software they want"]}'::jsonb, '{"answer": 1, "explain": "Copying software without permission is software piracy — a breach of the Copyright, Designs and Patents Act, not the Computer Misuse Act."}'::jsonb),
('computer-science:1-6-1b-legislation:misc:df4fb6f1', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Confusing the Data Protection Act with the Freedom of Information Act.</p><p><strong>✅ The correct idea:</strong> They point in <strong>opposite directions</strong>. The <strong>Data Protection Act</strong> <strong>protects</strong> individuals'' <strong>personal</strong> data (keeping it private and secure). The <strong>Freedom of Information Act</strong> <strong>opens up</strong> information held by <strong>public bodies</strong> so the public can request it. One keeps data private; the other makes information public.</p>", "question": "Which law would a member of the public use to ask their local hospital how it spends its budget?", "options": ["The Data Protection Act 2018, because the budget information is personal data belonging to the hospital itself", "The Freedom of Information Act 2000, because it lets the public request information held by public authorities", "The Computer Misuse Act 1990, because the budget figures are all stored on the hospital''s computer systems", "The Copyright, Designs and Patents Act 1988, because the hospital created the budget report as its own work"]}'::jsonb, '{"answer": 1, "explain": "Requesting information from a public body (the hospital) is exactly what the Freedom of Information Act allows."}'::jsonb),
('computer-science:1-6-1b-legislation:misc:744d4a54', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Getting the Acts'' names or years muddled (e.g. ''Data Misuse Act'').</p><p><strong>✅ The correct idea:</strong> Learn the exact names and years: <strong>Data Protection Act 2018</strong>, <strong>Computer Misuse Act 1990</strong>, <strong>Copyright, Designs and Patents Act 1988</strong>. Examiners usually allow small slips, but knowing them precisely avoids confusing two different laws — the years also help you keep them apart.</p>", "question": "Which of these is the correct name of a real piece of UK computer legislation?", "options": ["The Data Misuse and Hacking Prevention Act, which is used to protect all personal data held by companies", "The Computer Misuse Act 1990", "The Digital Privacy and Software Copying Act, which covers both personal data and the copying of software", "The Internet Safety and Information Freedom Act, which controls what can be posted onto social media websites"]}'::jsonb, '{"answer": 1, "explain": "The Computer Misuse Act 1990 is a real Act. The other names are invented — knowing the correct names and years prevents this mistake."}'::jsonb),
('computer-science:1-6-1b-legislation:misc:bfda9bfb', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking the Data Protection Act stops an organisation from storing ANY personal data at all.</p><p><strong>✅ The correct idea:</strong> The DPA does <strong>not</strong> ban storing personal data — organisations need it to function. It sets <strong>rules</strong>: get <strong>consent</strong>, keep it <strong>secure</strong>, use it only for the <strong>stated purpose</strong>, keep it <strong>accurate</strong>, and <strong>not longer than needed</strong>. It controls <strong>how</strong> data is handled, not whether it can be held at all.</p>", "question": "What does the Data Protection Act require of an organisation that stores personal data?", "options": ["That it must never store any personal data about any person under any circumstances whatsoever at all", "That it handles the data properly — with consent, kept secure, accurate, and only for as long as needed", "That it publishes all of the personal data it holds so that the information is open to the general public", "That it sells the personal data on to another company as soon as it has finished using the data itself"]}'::jsonb, '{"answer": 1, "explain": "The DPA controls HOW data is handled (consent, security, accuracy, retention) — it does not ban storing personal data outright."}'::jsonb),
('computer-science:1-6-1b-legislation:tips:1fe5f4d3', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'tips', 'mcq', 1, '{"readingTitle": "tip — The scenario → law matching skill", "reading": "<p>The most common question gives a scenario and asks which law applies — as a tick-grid, or \"Identify the legislation…\". Learn these signature links:</p>\n<ul>\n<li><strong>Personal data</strong> mishandled/shared/leaked → <strong>Data Protection Act 2018</strong></li>\n<li><strong>Accessing/changing a system</strong> without permission (hacking, malware) → <strong>Computer Misuse Act 1990</strong></li>\n<li><strong>Copying someone''s work</strong> (software, image, music, logo) → <strong>Copyright, Designs and Patents Act 1988</strong></li>\n<li><strong>Requesting info from a public body</strong> → <strong>Freedom of Information Act 2000</strong></li>\n</ul>\n<p><strong>The classic trap:</strong> \"a company storing customers'' data\" is <strong>Data Protection</strong> — students often wrongly pick Computer Misuse or Copyright here. Read for the key idea: <em>data</em>, <em>access</em>, <em>copying</em>, or <em>public information</em>?</p>", "question": "A youth centre stores personal data about the young people who attend. Which legislation must it follow?", "options": ["The Computer Misuse Act 1990, because the data is being kept on the youth centre''s own computer systems", "The Data Protection Act 2018, because it governs how organisations must handle people''s personal data", "The Copyright, Designs and Patents Act 1988, because the youth centre created the records that it is storing", "The Freedom of Information Act 2000, because the young people can ask to see the data that is held on them"]}'::jsonb, '{"answer": 1, "explain": "Storing personal data means following the Data Protection Act — the classic trap is wrongly choosing Computer Misuse or Copyright."}'::jsonb),
('computer-science:1-6-1b-legislation:tips:44afdefe', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'tips', 'mcq', 1, '{"readingTitle": "explain — Describe a law''s purpose — say what it protects and forbids", "reading": "<p>When asked to \"identify one piece of legislation… and describe it\", you need <strong>two things</strong>:</p>\n<ul>\n<li><strong>Identify (1 mark):</strong> the correct, named Act.</li>\n<li><strong>Describe (1+ marks):</strong> what it <strong>protects</strong> or what it makes <strong>illegal</strong>, ideally with a relevant detail.</li>\n</ul>\n<p><strong>Example (data storage):</strong> \"The <strong>Data Protection Act 2018</strong> <em>(identify)</em>. It controls how organisations store and use people''s <strong>personal data</strong>, requiring it to be kept <strong>secure</strong> and only used with <strong>consent</strong> <em>(describe)</em>.\"</p>\n<p>Just naming the Act is usually only half the marks — always add what it does.</p>", "question": "A 2-mark question says ''Identify one law the club must follow when storing members'' data, and describe it.'' What earns the second mark?", "options": ["Writing the name of the Act a second time in slightly different words to make the answer look longer", "Describing what the Act does, e.g. it requires personal data to be kept secure and used only with consent", "Giving the exact date and time at which the law was originally passed by parliament many years ago", "Naming a second, completely different law that has nothing to do with the storing of personal data at all"]}'::jsonb, '{"answer": 1, "explain": "The first mark is naming the Act; the second comes from describing what it does — e.g. keeping personal data secure, used with consent."}'::jsonb),
('computer-science:1-6-1b-legislation:tips:324e84b9', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'tips', 'mcq', 1, '{"readingTitle": "tip — Keep the three main Acts crisply apart", "reading": "<p>One line each — memorise these and you''ll rarely pick the wrong law:</p>\n<ul>\n<li><strong>Data Protection Act 2018</strong> = my <strong>data</strong> (personal information kept safe).</li>\n<li><strong>Computer Misuse Act 1990</strong> = my <strong>system</strong> (no hacking or malware).</li>\n<li><strong>Copyright, Designs and Patents Act 1988</strong> = my <strong>work</strong> (no copying software, music, images).</li>\n</ul>\n<p>Three words: <strong>data, system, work</strong>. Match the scenario to one of those, and you''ve almost certainly found the right Act.</p>", "question": "Using the ''data, system, work'' shortcut, which Act covers someone hacking into a company''s network?", "options": ["The Data Protection Act, because a network always contains at least some personal data about people", "The Computer Misuse Act 1990, because hacking into a system without permission is misusing that system", "The Copyright, Designs and Patents Act, because the company''s network setup is its own original design work", "The Freedom of Information Act, because the hacker was only ever trying to find out information they wanted"]}'::jsonb, '{"answer": 1, "explain": "Hacking a system is the ''system'' case — the Computer Misuse Act 1990, which forbids unauthorised access."}'::jsonb),
('computer-science:1-6-1b-legislation:fib:826a5d30', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'fib', 'fib', 1, '{"question": "The _____ Act 1990 makes it illegal to access or change a computer system without permission.", "blankOptions": {"B1": ["modification", "piracy", "Computer Misuse", "Information"]}}'::jsonb, '{"blanks": {"B1": "Computer Misuse"}}'::jsonb),
('computer-science:1-6-1b-legislation:fib:e5d40d0b', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'fib', 'fib', 1, '{"question": "The Data _____ Act 2018 controls how organisations collect, store and use people''s personal data.", "blankOptions": {"B1": ["Computer Misuse", "consent", "modification", "Protection"]}}'::jsonb, '{"blanks": {"B1": "Protection"}}'::jsonb),
('computer-science:1-6-1b-legislation:fib:dbd03063', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'fib', 'fib', 1, '{"question": "The Copyright, Designs and Patents Act 1988 protects original work such as software, music and _____.", "blankOptions": {"B1": ["secure", "images", "modification", "Computer Misuse"]}}'::jsonb, '{"blanks": {"B1": "images"}}'::jsonb),
('computer-science:1-6-1b-legislation:fib:3e7559b9', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'fib', 'fib', 1, '{"question": "Illegally copying and sharing software is called software _____ and breaks the Copyright Act.", "blankOptions": {"B1": ["Protection", "Information", "piracy", "modification"]}}'::jsonb, '{"blanks": {"B1": "piracy"}}'::jsonb),
('computer-science:1-6-1b-legislation:fib:0250de75', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'fib', 'fib', 1, '{"question": "Under the Data Protection Act, personal data must be kept _____ from unauthorised access.", "blankOptions": {"B1": ["Protection", "secure", "Computer Misuse", "images"]}}'::jsonb, '{"blanks": {"B1": "secure"}}'::jsonb),
('computer-science:1-6-1b-legislation:fib:5de2e770', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'fib', 'fib', 1, '{"question": "Spreading a virus that deletes files is ''unauthorised _____'' under the Computer Misuse Act.", "blankOptions": {"B1": ["piracy", "images", "consent", "modification"]}}'::jsonb, '{"blanks": {"B1": "modification"}}'::jsonb),
('computer-science:1-6-1b-legislation:fib:d2304bcf', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'fib', 'fib', 1, '{"question": "The Freedom of _____ Act 2000 lets the public request information held by public authorities.", "blankOptions": {"B1": ["Computer Misuse", "images", "Information", "consent"]}}'::jsonb, '{"blanks": {"B1": "Information"}}'::jsonb),
('computer-science:1-6-1b-legislation:fib:4d7e18fb', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'fib', 'fib', 1, '{"question": "Under the Data Protection Act, an organisation must get a person''s _____ before collecting their personal data.", "blankOptions": {"B1": ["consent", "piracy", "modification", "Protection"]}}'::jsonb, '{"blanks": {"B1": "consent"}}'::jsonb),
('computer-science:1-6-1b-legislation:match:98c542bc', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Data Protection Act 2018”?", "options": ["Permission a person gives for their personal data to be collected and used", "Illegally copying or sharing software, breaking the CDPA", "Changing or deleting data without permission, e.g. spreading a virus (CMA)", "Controls how organisations collect, store and use people''s personal data"]}'::jsonb, '{"answer": 3, "explain": "“Data Protection Act 2018” means: Controls how organisations collect, store and use people''s personal data"}'::jsonb),
('computer-science:1-6-1b-legislation:match:ddbdb6a1', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Computer Misuse Act 1990”?", "options": ["Makes it illegal to access or modify a computer system without permission", "Changing or deleting data without permission, e.g. spreading a virus (CMA)", "Information about an identifiable living person, protected by the DPA", "Gives the public the right to request information held by public authorities"]}'::jsonb, '{"answer": 0, "explain": "“Computer Misuse Act 1990” means: Makes it illegal to access or modify a computer system without permission"}'::jsonb),
('computer-science:1-6-1b-legislation:match:094ff5d3', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Copyright, Designs and Patents Act 1988”?", "options": ["Information about an identifiable living person, protected by the DPA", "Permission a person gives for their personal data to be collected and used", "Illegally copying or sharing software, breaking the CDPA", "Protects original work such as software, music, images and writing"]}'::jsonb, '{"answer": 3, "explain": "“Copyright, Designs and Patents Act 1988” means: Protects original work such as software, music, images and writing"}'::jsonb),
('computer-science:1-6-1b-legislation:match:15a94627', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Freedom of Information Act 2000”?", "options": ["Makes it illegal to access or modify a computer system without permission", "Illegally copying or sharing software, breaking the CDPA", "Getting into a computer system or account without permission (a CMA offence)", "Gives the public the right to request information held by public authorities"]}'::jsonb, '{"answer": 3, "explain": "“Freedom of Information Act 2000” means: Gives the public the right to request information held by public authorities"}'::jsonb),
('computer-science:1-6-1b-legislation:match:fc119c0e', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Personal data”?", "options": ["Protects original work such as software, music, images and writing", "Information about an identifiable living person, protected by the DPA", "Changing or deleting data without permission, e.g. spreading a virus (CMA)", "Getting into a computer system or account without permission (a CMA offence)"]}'::jsonb, '{"answer": 1, "explain": "“Personal data” means: Information about an identifiable living person, protected by the DPA"}'::jsonb),
('computer-science:1-6-1b-legislation:match:4e6b294b', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Unauthorised access”?", "options": ["Permission a person gives for their personal data to be collected and used", "Gives the public the right to request information held by public authorities", "A body such as a council or school that FoI requests can be made to", "Getting into a computer system or account without permission (a CMA offence)"]}'::jsonb, '{"answer": 3, "explain": "“Unauthorised access” means: Getting into a computer system or account without permission (a CMA offence)"}'::jsonb),
('computer-science:1-6-1b-legislation:match:30b27f3a', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Unauthorised modification”?", "options": ["Changing or deleting data without permission, e.g. spreading a virus (CMA)", "Information about an identifiable living person, protected by the DPA", "A person appointed to ensure an organisation follows data protection rules", "Protects original work such as software, music, images and writing"]}'::jsonb, '{"answer": 0, "explain": "“Unauthorised modification” means: Changing or deleting data without permission, e.g. spreading a virus (CMA)"}'::jsonb),
('computer-science:1-6-1b-legislation:match:b60b82ee', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Intellectual property”?", "options": ["A body such as a council or school that FoI requests can be made to", "Controls how organisations collect, store and use people''s personal data", "Protects original work such as software, music, images and writing", "Original work such as software or music that belongs to its creator"]}'::jsonb, '{"answer": 3, "explain": "“Intellectual property” means: Original work such as software or music that belongs to its creator"}'::jsonb),
('computer-science:1-6-1b-legislation:match:1223a9a4', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Software piracy”?", "options": ["A body such as a council or school that FoI requests can be made to", "Illegally copying or sharing software, breaking the CDPA", "Changing or deleting data without permission, e.g. spreading a virus (CMA)", "Controls how organisations collect, store and use people''s personal data"]}'::jsonb, '{"answer": 1, "explain": "“Software piracy” means: Illegally copying or sharing software, breaking the CDPA"}'::jsonb),
('computer-science:1-6-1b-legislation:match:f55d4b50', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Consent”?", "options": ["Controls how organisations collect, store and use people''s personal data", "Original work such as software or music that belongs to its creator", "Permission a person gives for their personal data to be collected and used", "A person appointed to ensure an organisation follows data protection rules"]}'::jsonb, '{"answer": 2, "explain": "“Consent” means: Permission a person gives for their personal data to be collected and used"}'::jsonb),
('computer-science:1-6-1b-legislation:match:37ab67d8', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Data protection officer”?", "options": ["Illegally copying or sharing software, breaking the CDPA", "Controls how organisations collect, store and use people''s personal data", "A person appointed to ensure an organisation follows data protection rules", "Protects original work such as software, music, images and writing"]}'::jsonb, '{"answer": 2, "explain": "“Data protection officer” means: A person appointed to ensure an organisation follows data protection rules"}'::jsonb),
('computer-science:1-6-1b-legislation:match:e2ac56ec', 'computer-science', 'computer-science:1-6-1b-legislation', '1.6.1b Legislation', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Public authority”?", "options": ["A body such as a council or school that FoI requests can be made to", "A person appointed to ensure an organisation follows data protection rules", "Gives the public the right to request information held by public authorities", "Information about an identifiable living person, protected by the DPA"]}'::jsonb, '{"answer": 0, "explain": "“Public authority” means: A body such as a council or school that FoI requests can be made to"}'::jsonb),
('computer-science:1-6-1c-software-licensing:mcq:90f65932', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'mcq', 'mcq', 1, '{"question": "What does a software licence actually give the person who buys it?", "options": ["Full ownership of the software''s source code, which they are then completely free to sell on to somebody else", "Permission to use the software under certain terms, while the creator keeps the copyright", "A physical piece of hardware that must be connected before the software is allowed to run on the computer", "A promise from the developer that the software will always run perfectly and never once need to be updated"]}'::jsonb, '{"answer": 1, "explain": "A licence grants permission to use the software under set terms; the creator keeps the copyright — you don''t own the software itself."}'::jsonb),
('computer-science:1-6-1c-software-licensing:mcq:f009a9f1', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'mcq', 'mcq', 1, '{"question": "Which of these is a feature of open source software?", "options": ["The company that made it keeps the source code completely secret so that no user is ever able to see it", "Its source code is available, and users are allowed to change it and redistribute it", "It always costs a large one-off fee, which must be paid before it can be downloaded and installed", "It can only be installed and used on one single computer, which must be registered with the developer first"]}'::jsonb, '{"answer": 1, "explain": "Open source software provides its source code and allows users to modify and redistribute it — usually for free."}'::jsonb),
('computer-science:1-6-1c-software-licensing:mcq:95f6aa8f', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'mcq', 'mcq', 1, '{"question": "Which of these is a feature of proprietary software?", "options": ["Anyone at all is free to view its source code, change it however they wish, and then redistribute their version", "You usually pay for it, and its source code is kept secret so users cannot change it", "It is always written and maintained entirely by unpaid volunteers working together in an online community", "It must, by law, be given away completely free of charge to any person or business that asks the company for it"]}'::jsonb, '{"answer": 1, "explain": "Proprietary (closed source) software is usually paid for and keeps its source code hidden, so users cannot change it."}'::jsonb),
('computer-science:1-6-1c-software-licensing:mcq:6f8852dd', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'mcq', 'mcq', 1, '{"question": "A company needs software that is reliable and comes with professional support and regular updates. Which is the better fit?", "options": ["Open source software", "Proprietary software", "Software with no licence of any kind", "Software that is still only a rough, unfinished test version"]}'::jsonb, '{"answer": 1, "explain": "Proprietary software typically offers reliability, official support and regular updates — a good fit for a business that needs dependability."}'::jsonb),
('computer-science:1-6-1c-software-licensing:mcq:52b101bf', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'mcq', 'mcq', 1, '{"question": "Which is a genuine benefit of open source software?", "options": ["It always comes with a guaranteed telephone support line staffed by the original developers around the clock", "It is usually free and can be changed and customised because its source code is available", "It is always more secure than proprietary software because absolutely nobody can ever see how it works inside", "It can never contain any bugs, because so many different community volunteers have looked at all of the code"]}'::jsonb, '{"answer": 1, "explain": "Open source is usually free and can be customised because its source code is open — but it does not guarantee support, security or a bug-free program."}'::jsonb),
('computer-science:1-6-1c-software-licensing:mcq:96b45954', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'mcq', 'mcq', 1, '{"question": "Which is a drawback of proprietary software?", "options": ["Its source code is available for anyone to change, which can make different copies behave inconsistently", "It usually costs money and you cannot change it, because the source code is kept hidden from you", "It is developed only by volunteers, so there is never anyone available to provide official support for it", "It can be freely copied and shared, which makes it very hard for the company to earn any money from it"]}'::jsonb, '{"answer": 1, "explain": "Proprietary software costs money and cannot be customised (its source code is hidden) — the other options actually describe open source."}'::jsonb),
('computer-science:1-6-1c-software-licensing:mcq:b6e24342', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'mcq', 'mcq', 1, '{"question": "Which statement about copyright and these licence types is correct?", "options": ["Only proprietary software is protected by copyright; open source software has no copyright protection at all", "Both proprietary and open source software are protected by copyright", "Neither proprietary nor open source software is ever protected by copyright once it has been released to users", "Copyright applies to open source software but is completely removed from proprietary software when it is sold"]}'::jsonb, '{"answer": 1, "explain": "Both types are protected by copyright — open source simply grants users more permissions (to view, change and share) than proprietary does."}'::jsonb),
('computer-science:1-6-1c-software-licensing:mcq:db010068', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'mcq', 'mcq', 1, '{"question": "A developer wants software they can adapt and build on, and they want to avoid licence costs. Which is the better fit?", "options": ["Proprietary software", "Open source software", "Software that has had all of its copyright legally and permanently removed by the developer", "A trial version of proprietary software that stops working completely after only thirty days"]}'::jsonb, '{"answer": 1, "explain": "Open source suits a developer who wants to adapt the software and avoid cost, because the source code is available and it is usually free."}'::jsonb),
('computer-science:1-6-1c-software-licensing:mcq:bcfca14f', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'mcq', 'mcq', 1, '{"question": "What is a Creative Commons licence used for?", "options": ["Permanently removing all copyright from a piece of work so that it belongs to nobody and can never be owned again", "Letting a creator share work such as videos or images under conditions they choose, like requiring credit", "Guaranteeing that a piece of open source software will always keep working on every future operating system", "Forcing everyone who wants to view a creator''s work to pay a fee to the creator before they are allowed to see it"]}'::jsonb, '{"answer": 1, "explain": "A Creative Commons licence lets a creator share their work under chosen conditions (such as attribution) while keeping some rights."}'::jsonb),
('computer-science:1-6-1c-software-licensing:mcq:b2a894ef', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'mcq', 'mcq', 1, '{"question": "William releases his videos under a Creative Commons licence that requires attribution. What must other people do to use them?", "options": ["Nothing at all is required of them, because a Creative Commons licence removes every single condition on the work", "Give William credit as the creator when they use his videos, following the licence''s conditions", "Pay William a fixed licence fee each and every time that they choose to use one of his videos anywhere", "Ask William for his written permission in advance before they are allowed to use any of the videos at all"]}'::jsonb, '{"answer": 1, "explain": "An attribution Creative Commons licence requires users to credit the creator — that is the condition William has set, so no separate permission is needed."}'::jsonb),
('computer-science:1-6-1c-software-licensing:mcq:d4a704cb', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'mcq', 'mcq', 1, '{"question": "Why might a school with little money and skilled IT staff choose open source software?", "options": ["Because open source software is the only type that is actually legal for a school to install on its computers", "Because it is usually free and the staff have the skills to set it up and customise it themselves", "Because open source software always comes with a paid support contract that a school is required to buy", "Because open source software cannot be changed, which makes it much simpler for the school to manage safely"]}'::jsonb, '{"answer": 1, "explain": "Open source is usually free and can be customised; a school with skilled staff can support it themselves, saving on licence costs."}'::jsonb),
('computer-science:1-6-1c-software-licensing:mcq:c69436f3', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'mcq', 'mcq', 1, '{"question": "Which pairing of a user with the most suitable licence is best justified?", "options": ["A hospital that needs guaranteed, reliable support → open source, because a community will always help quickly", "A large business that needs dependable, supported software → proprietary, because it offers official support", "A developer wanting to freely adapt the code → proprietary, because the hidden source code is easier to change", "A charity with no money and skilled staff → proprietary, because paying for software is always the safest choice"]}'::jsonb, '{"answer": 1, "explain": "A business needing dependable, supported software is well matched to proprietary. The other pairings match the user to the wrong licence."}'::jsonb),
('computer-science:1-6-1c-software-licensing:tf:0d3d4b19', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'tf', 'tf', 1, '{"question": "When you buy proprietary software you are buying a licence to use it, not the copyright."}'::jsonb, '{"answer": true, "explain": "Correct — you buy permission to use it under set terms; the creator keeps the copyright."}'::jsonb),
('computer-science:1-6-1c-software-licensing:tf:40180d81', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'tf', 'tf', 1, '{"question": "Open source software makes its source code available so users can change and redistribute it."}'::jsonb, '{"answer": true, "explain": "Correct — that is the defining feature of open source, and it is usually free as well."}'::jsonb),
('computer-science:1-6-1c-software-licensing:tf:ff821c00', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'tf', 'tf', 1, '{"question": "Proprietary software lets users freely view and edit its source code."}'::jsonb, '{"answer": false, "explain": "Proprietary (closed source) software keeps its source code secret — users cannot view or change it."}'::jsonb),
('computer-science:1-6-1c-software-licensing:tf:520ef6a1', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'tf', 'tf', 1, '{"question": "A benefit of proprietary software is that it usually comes with official support and updates."}'::jsonb, '{"answer": true, "explain": "Correct — reliable official support and regular updates are key benefits of proprietary software."}'::jsonb),
('computer-science:1-6-1c-software-licensing:tf:e3fadad8', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'tf', 'tf', 1, '{"question": "A drawback of open source software is that there may be no official support if something goes wrong."}'::jsonb, '{"answer": true, "explain": "Correct — open source often lacks a company to provide official support, and its quality can vary."}'::jsonb),
('computer-science:1-6-1c-software-licensing:tf:f77b0708', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'tf', 'tf', 1, '{"question": "Open source software has no copyright protection at all."}'::jsonb, '{"answer": false, "explain": "Both open source and proprietary software are protected by copyright — open source simply grants users more permissions."}'::jsonb),
('computer-science:1-6-1c-software-licensing:tf:09f7fab2', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'tf', 'tf', 1, '{"question": "A Creative Commons licence lets a creator share their work while keeping some rights."}'::jsonb, '{"answer": true, "explain": "Correct — Creative Commons lets creators set conditions (like attribution) for how others may use and share their work."}'::jsonb),
('computer-science:1-6-1c-software-licensing:tf:29649f38', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'tf', 'tf', 1, '{"question": "Proprietary software is always the best choice for every situation."}'::jsonb, '{"answer": false, "explain": "There is no single best choice — it depends on the user''s needs. Open source can be better when cost and customisation matter."}'::jsonb),
('computer-science:1-6-1c-software-licensing:learn:2a788ab3', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'learn', 'mcq', 1, '{"readingTitle": "What is a software licence?", "reading": "<h4>You buy permission to use software, not the software itself</h4>\n<ul>\n<li>A <strong>software licence</strong> is the set of <strong>legal terms</strong> that says <strong>how you are allowed to use</strong> a piece of software — for example how many computers you can install it on, and whether you may change or share it.</li>\n<li>When you \"buy\" software you are really buying (or agreeing to) a <strong>licence to use it</strong>; the <strong>creator keeps the copyright</strong>.</li>\n<li>The two main types you must know are <strong>proprietary (closed source)</strong> and <strong>open source</strong>. A third idea, <strong>Creative Commons</strong>, is a way of licensing creative work such as videos and images.</li>\n</ul>", "question": "What is a software licence?", "options": ["A physical certificate printed on paper that must always be kept inside the box the software was sold in", "The legal terms that set out how you are allowed to use a piece of software", "A special piece of hardware that has to be plugged into the computer before the software will run", "A guarantee that the software will never contain any bugs or errors of any kind for as long as it is used"]}'::jsonb, '{"answer": 1, "explain": "A software licence is the legal terms setting out how you may use the software — the creator keeps the copyright even after you buy a licence."}'::jsonb),
('computer-science:1-6-1c-software-licensing:learn:d7bfd7c5', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'learn', 'mcq', 1, '{"readingTitle": "Proprietary (closed source) software", "reading": "<h4>Owned by a company, source code hidden</h4>\n<ul>\n<li><strong>Proprietary</strong> (or <strong>closed source</strong>) software is owned by the company that made it. You usually <strong>pay</strong> for a licence to use it.</li>\n<li>The <strong>source code is kept secret</strong> — users <strong>cannot see or change</strong> it — and you are <strong>not allowed to copy or redistribute</strong> the software.</li>\n<li>Examples include <strong>Microsoft Windows</strong>, <strong>Microsoft Office</strong> and <strong>Adobe Photoshop</strong>.</li>\n</ul>", "question": "Which statement is true of proprietary (closed source) software?", "options": ["Its source code is freely available, so any user is able to read it, change it and then share their new version", "You usually pay for it, and its source code is kept secret so users cannot change it", "It is always completely free of charge, but it can only ever be installed on one single computer at a time", "It can be legally copied and given away to as many other people as the user likes, at absolutely no cost"]}'::jsonb, '{"answer": 1, "explain": "Proprietary software is usually paid for and keeps its source code secret, so users cannot view or change it or freely redistribute it."}'::jsonb),
('computer-science:1-6-1c-software-licensing:learn:147fd94d', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'learn', 'mcq', 1, '{"readingTitle": "Open source software", "reading": "<h4>Source code available, free to use and change</h4>\n<ul>\n<li><strong>Open source</strong> software is released with its <strong>source code available</strong> to everyone.</li>\n<li>It is usually <strong>free</strong>, and users are allowed to <strong>view, modify (change) and redistribute</strong> it. It is often developed and improved by a <strong>community</strong> of volunteers.</li>\n<li>Examples include the <strong>Linux</strong> operating system, the <strong>Firefox</strong> browser and the <strong>GIMP</strong> image editor.</li>\n</ul>", "question": "What is a key feature of open source software?", "options": ["It is owned by a single company that keeps the source code completely secret from every one of its users", "Its source code is available, so users can view, change and redistribute it, and it is usually free", "It can only be used by professional software developers who have first paid for an expensive yearly licence", "It is a physical product that is always sold on a disc rather than being made available to download online"]}'::jsonb, '{"answer": 1, "explain": "Open source software makes its source code available so users can view, change and redistribute it, and it is usually free."}'::jsonb),
('computer-science:1-6-1c-software-licensing:learn:51034edc', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'learn', 'mcq', 1, '{"readingTitle": "Proprietary software — benefits and drawbacks", "reading": "<h4>Weighing up closed source software</h4>\n<ul>\n<li><strong>Benefits:</strong> it is usually <strong>well tested and reliable</strong>, comes with <strong>official support</strong> and <strong>regular updates</strong>, and is often <strong>polished and easy to use</strong> — good for a business that needs dependable software.</li>\n<li><strong>Drawbacks:</strong> it <strong>costs money</strong> (sometimes a lot), you <strong>cannot change or customise</strong> it to your own needs because the source code is hidden, and you depend on the company to keep supporting it.</li>\n</ul>", "question": "Which is a benefit of proprietary software compared with open source?", "options": ["It can always be copied and shared freely with anyone, at no cost, because the company positively encourages it", "It usually comes with official support and regular updates from the company that made it", "Its source code can be freely changed by the user to add any new feature that they happen to want", "It is developed only by unpaid community volunteers, which is what makes it so reliable and well tested"]}'::jsonb, '{"answer": 1, "explain": "A key benefit of proprietary software is official support and regular updates from the company — the other options actually describe open source."}'::jsonb),
('computer-science:1-6-1c-software-licensing:learn:188995be', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'learn', 'mcq', 1, '{"readingTitle": "Open source software — benefits and drawbacks", "reading": "<h4>Weighing up open source software</h4>\n<ul>\n<li><strong>Benefits:</strong> it is usually <strong>free</strong>, you can <strong>change and customise</strong> it because the source code is available, and a <strong>community</strong> can improve it and fix problems.</li>\n<li><strong>Drawbacks:</strong> there may be <strong>no official support</strong> if something goes wrong, quality can <strong>vary</strong>, and you may need <strong>technical skill</strong> to set it up or modify it. Its security relies on the community spotting and fixing issues.</li>\n</ul>", "question": "Which is a drawback of open source software compared with proprietary?", "options": ["It usually costs a very large amount of money to buy before a person is allowed to install and use it", "There may be no official support to turn to if something goes wrong, and quality can vary between versions", "Its source code is kept completely hidden, so it is impossible for anyone to fix a problem with the program", "It can never be changed or customised in any way at all, because doing so is against the terms of its licence"]}'::jsonb, '{"answer": 1, "explain": "Open source may lack official support and its quality can vary — the other options describe proprietary software or are simply untrue of open source."}'::jsonb),
('computer-science:1-6-1c-software-licensing:learn:85f54651', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'learn', 'mcq', 1, '{"readingTitle": "Choosing and recommending a licence", "reading": "<h4>Match the licence to the situation</h4>\n<ul>\n<li>Questions often ask you to <strong>recommend</strong> a licence for a scenario and <strong>justify</strong> it. There is no single right answer — it depends on what the user <strong>needs</strong>.</li>\n<li>Lean <strong>proprietary</strong> when the user needs <strong>reliability and official support</strong>, has money to spend, and does not need to change the software — e.g. a <strong>business</strong> that needs dependable, supported tools.</li>\n<li>Lean <strong>open source</strong> when the user wants to <strong>save money</strong>, values being able to <strong>adapt</strong> the software, and has the <strong>skills</strong> (or a community) to support it — e.g. a <strong>developer</strong> building on top of it.</li>\n<li>Remember: <strong>both</strong> types are still protected by <strong>copyright</strong>.</li>\n</ul>", "question": "A business needs reliable, well-supported software and is happy to pay for it. Which licence is the better fit, and why?", "options": ["Open source, because a large community of unpaid volunteers will always fix any problem far faster than a company ever possibly could", "Proprietary, because it typically offers reliability and official support, which the business values and can pay for", "Open source, because the business will definitely want to rewrite the software''s source code to suit its own needs", "Proprietary, because it is the only kind of software that it is actually legal for a business to use at work"]}'::jsonb, '{"answer": 1, "explain": "A business that values reliability and support, and can pay, is a good fit for proprietary software. Both licence types are legal to use."}'::jsonb),
('computer-science:1-6-1c-software-licensing:learn:a6d7ead8', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'learn', 'mcq', 1, '{"readingTitle": "Creative Commons licences", "reading": "<h4>Sharing creative work with conditions</h4>\n<ul>\n<li>A <strong>Creative Commons (CC)</strong> licence is a way for a creator of work such as <strong>videos, images, music or writing</strong> to let <strong>others use and share it</strong>, while <strong>keeping some rights</strong>.</li>\n<li>The creator chooses the <strong>conditions</strong>. Common ones include: others must give <strong>credit (attribution)</strong> to the creator; the work may or may not be used for <strong>commercial (money-making)</strong> purposes; and any new version may have to be <strong>shared under the same licence</strong>.</li>\n<li>It sits between \"all rights reserved\" (normal copyright) and fully free — the creator says in advance <strong>what others are allowed to do</strong>, so they don''t have to ask permission each time.</li>\n</ul>", "question": "How does releasing a video under a Creative Commons licence affect how others can use it?", "options": ["It means absolutely nobody else is ever allowed to watch, use or share the video without paying a fee first", "It lets others use and share the video under conditions the creator sets, such as giving credit", "It transfers the full copyright of the video to whoever downloads it first, so the creator loses all rights", "It guarantees that the video can only ever be used by large companies for their paid advertising campaigns"]}'::jsonb, '{"answer": 1, "explain": "A Creative Commons licence lets others use and share the work under conditions the creator chooses (such as attribution) — the creator keeps some rights."}'::jsonb),
('computer-science:1-6-1c-software-licensing:misc:7abeb7c7', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking open source software is exactly the same as ''freeware'' — just free software.</p><p><strong>✅ The correct idea:</strong> The key point of <strong>open source</strong> is that the <strong>source code is available</strong> to view, change and share — not just that it is free. Some free software (freeware) is still <strong>closed source</strong>: you can use it for free but you <strong>cannot see or change</strong> its code. Open source is about <strong>openness of the code</strong>, not only price.</p>", "question": "What most defines open source software?", "options": ["Simply that it does not cost any money, which is the only thing that really separates it from other software", "That its source code is available for users to view, change and redistribute", "That it can only ever be used by large companies who employ their own team of professional programmers", "That it is always more powerful and more reliable than any proprietary software could possibly ever be"]}'::jsonb, '{"answer": 1, "explain": "Open source is defined by its source code being available to view, change and share — not merely by being free of charge."}'::jsonb),
('computer-science:1-6-1c-software-licensing:misc:befec0cc', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Believing open source software has no copyright, so you can do anything you like with it.</p><p><strong>✅ The correct idea:</strong> Open source software <strong>is</strong> protected by <strong>copyright</strong> — the licence simply <strong>grants users permission</strong> to view, change and share the code, often on conditions (like keeping it open source). It is not a free-for-all; you must still follow the terms of its licence.</p>", "question": "Is open source software protected by copyright?", "options": ["No — releasing software as open source completely removes all of its copyright protection straight away", "Yes — it is protected by copyright, and its licence grants users permission to view, change and share it", "No — copyright only ever applies to music and films, and it has never applied to computer software at all", "Yes — but only if the user pays an additional fee to the developer in order to activate that protection"]}'::jsonb, '{"answer": 1, "explain": "Open source software is protected by copyright; the licence grants extra permissions, but users must still follow its terms."}'::jsonb),
('computer-science:1-6-1c-software-licensing:misc:4c769602', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Assuming proprietary software is always better because you pay for it.</p><p><strong>✅ The correct idea:</strong> Paying does bring real benefits — <strong>reliability, support, updates</strong> — but proprietary software also has <strong>drawbacks</strong> (cost, no customisation). For some users, <strong>open source is the better choice</strong>. The ''best'' licence <strong>depends on the situation</strong>: what the user needs, their budget and their skills.</p>", "question": "When might open source software be a better choice than proprietary?", "options": ["Never — proprietary software is always the better choice because it is the only option that costs any money", "When the user wants to save money and be able to customise the software, and can support it themselves", "Only when the user has absolutely no interest in the software working reliably or being supported at all", "Only when the user is legally banned from buying any proprietary software for some particular reason"]}'::jsonb, '{"answer": 1, "explain": "Open source suits users who want to save money and customise the software and who can support it themselves — the best choice depends on the situation."}'::jsonb),
('computer-science:1-6-1c-software-licensing:misc:863d68ff', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Confusing ''closed source'' and ''open source'' — mixing up which one hides the code.</p><p><strong>✅ The correct idea:</strong> <strong>Closed source (proprietary)</strong> = code is <strong>hidden</strong>, you can''t change it. <strong>Open source</strong> = code is <strong>open</strong>, you can change it. The name tells you: is the source code <strong>open</strong> (visible) or <strong>closed</strong> (hidden)?</p>", "question": "Which type of software keeps its source code hidden from users?", "options": ["Open source software, because the word ''open'' actually refers to it being openly available to buy in shops", "Proprietary (closed source) software, because its source code is kept secret and cannot be changed", "Both types keep their source code hidden, so there is no real difference between them for the user at all", "Neither type hides its source code, because by law all software code must be published when it is released"]}'::jsonb, '{"answer": 1, "explain": "Proprietary (closed source) software hides its source code; open source makes it available. The name signals whether the code is open or closed."}'::jsonb),
('computer-science:1-6-1c-software-licensing:misc:702fd6f5', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking a Creative Commons licence means the work is free to use however you want.</p><p><strong>✅ The correct idea:</strong> Creative Commons lets a creator <strong>share</strong> their work, but usually <strong>with conditions</strong> — most commonly requiring <strong>attribution</strong> (crediting the creator), and sometimes forbidding <strong>commercial use</strong> or requiring you to <strong>share alike</strong>. You must <strong>follow the specific conditions</strong> the creator chose, not just do anything you like.</p>", "question": "Someone finds a photo under a Creative Commons licence that requires attribution. What must they do to use it?", "options": ["Nothing — a Creative Commons licence means the photo can be used in any way at all with no conditions", "Credit the photographer as the creator, following the attribution condition the licence sets", "Buy the full copyright to the photo from the photographer before they are allowed to use it anywhere", "Change the photo so much that the original photographer would no longer be able to recognise it as theirs"]}'::jsonb, '{"answer": 1, "explain": "An attribution licence requires the user to credit the creator — Creative Commons work comes with conditions that must be followed."}'::jsonb),
('computer-science:1-6-1c-software-licensing:tips:5acdbaae', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'tips', 'mcq', 1, '{"readingTitle": "tip — Feature vs benefit vs drawback — know which the question wants", "reading": "<p>Licensing questions ask for <strong>features</strong>, <strong>benefits</strong>, <strong>drawbacks</strong>, or a <strong>recommendation</strong> — and they are different things:</p>\n<ul>\n<li><strong>Feature</strong> = a fact about it (\"the source code is available\").</li>\n<li><strong>Benefit</strong> = why that is good for the user (\"so it can be customised for free\").</li>\n<li><strong>Drawback</strong> = why it could be a problem (\"but there may be no official support\").</li>\n</ul>\n<p>If a question asks for a <strong>benefit</strong>, don''t just state a feature — say <strong>why it helps the user</strong>. And a \"give one benefit and one drawback\" question needs <strong>one of each</strong>, not two benefits.</p>", "question": "A question asks for one BENEFIT of open source software. Which answer earns the mark?", "options": ["Stating only the plain feature that the source code of the software happens to be available to look at", "Saying it is free and can be customised, so the user saves money and can adapt it to their needs", "Listing a clear drawback instead, such as the fact that there may be no official support available for it", "Naming a completely different piece of open source software without explaining anything about it at all"]}'::jsonb, '{"answer": 1, "explain": "A benefit says why the feature helps the user (free + customisable → saves money, can adapt it) — not just the bare feature, and not a drawback."}'::jsonb),
('computer-science:1-6-1c-software-licensing:tips:ed4156ef', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'tips', 'mcq', 1, '{"readingTitle": "explain — The ''recommend a licence and justify it'' question", "reading": "<p>A common question describes a scenario and asks you to <strong>recommend</strong> open source or proprietary and <strong>justify</strong> your choice. There is <strong>no single right answer</strong> — the marks are for the <strong>justification linked to the scenario</strong>.</p>\n<ul>\n<li>Pick the licence that fits the user''s <strong>needs</strong>: reliability + support + budget → <strong>proprietary</strong>; low cost + wanting to adapt it + having the skills → <strong>open source</strong>.</li>\n<li>Justify with the <strong>benefits</strong> of your choice AND, ideally, why the <strong>drawbacks</strong> of the other option matter for this user.</li>\n<li>Always tie it to the <strong>specific scenario</strong> (a business, a school, a solo developer…).</li>\n</ul>", "question": "On a ''recommend and justify a licence'' question, what earns the marks?", "options": ["Simply naming either open source or proprietary, without giving any reason at all for the particular choice", "A justification linked to the scenario, explaining why the chosen licence suits that user''s needs", "Explaining in detail how the computer''s processor runs the machine code of the software while it is in use", "Always recommending proprietary software, because it is the only choice that could ever be marked correct"]}'::jsonb, '{"answer": 1, "explain": "The marks are for the justification tied to the scenario — why the chosen licence fits that user — not just naming one, and either choice can be valid."}'::jsonb),
('computer-science:1-6-1c-software-licensing:tips:7fe1750b', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'tips', 'mcq', 1, '{"readingTitle": "tip — Explaining a Creative Commons licence", "reading": "<p>If asked how a <strong>Creative Commons</strong> licence affects the use of someone''s work, cover:</p>\n<ul>\n<li>It lets <strong>other people use and share</strong> the work <strong>without asking permission each time</strong>…</li>\n<li>…but <strong>under conditions the creator chooses</strong> — commonly <strong>attribution</strong> (give credit), sometimes <strong>non-commercial</strong> (no money-making use) or <strong>share-alike</strong> (share any new version the same way)…</li>\n<li>…and the creator still <strong>keeps some rights</strong> (it is not the same as giving up copyright).</li>\n</ul>\n<p>A strong answer names at least one <strong>specific condition</strong>, not just \"people can use it\".</p>", "question": "Which point would strengthen an answer about how a Creative Commons licence affects others'' use of a video?", "options": ["That the licence removes the creator''s copyright entirely, so the video now belongs to whoever downloads it", "That others may use and share it without asking each time, but must follow conditions such as giving credit", "That the video can only be watched by people who have first paid the creator a monthly subscription fee", "That the video will automatically stop playing after a set number of views unless it is bought outright"]}'::jsonb, '{"answer": 1, "explain": "A strong answer notes that others can use/share it without asking each time but must meet the creator''s conditions (e.g. attribution), and the creator keeps some rights."}'::jsonb),
('computer-science:1-6-1c-software-licensing:fib:13f923f9', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'fib', 'fib', 1, '{"question": "A software _____ sets out the legal terms of how you are allowed to use a piece of software.", "blankOptions": {"B1": ["support", "licence", "proprietary", "free"]}}'::jsonb, '{"blanks": {"B1": "licence"}}'::jsonb),
