('computer-science:1-6-1c-software-licensing:fib:57be09f4', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'fib', 'fib', 1, '{"question": "Open _____ software is released with its source code available so users can change and share it.", "blankOptions": {"B1": ["source", "copyright", "licence", "proprietary"]}}'::jsonb, '{"blanks": {"B1": "source"}}'::jsonb),
('computer-science:1-6-1c-software-licensing:fib:e0eb4bb1', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'fib', 'fib', 1, '{"question": "A benefit of proprietary software is that it usually comes with official _____ and regular updates.", "blankOptions": {"B1": ["copyright", "support", "Commons", "proprietary"]}}'::jsonb, '{"blanks": {"B1": "support"}}'::jsonb),
('computer-science:1-6-1c-software-licensing:fib:7f1a7250', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'fib', 'fib', 1, '{"question": "A benefit of open source software is that it is usually _____ and can be customised.", "blankOptions": {"B1": ["support", "licence", "code", "free"]}}'::jsonb, '{"blanks": {"B1": "free"}}'::jsonb),
('computer-science:1-6-1c-software-licensing:fib:a4f21522', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'fib', 'fib', 1, '{"question": "The human-readable program instructions written by developers are called the source _____.", "blankOptions": {"B1": ["licence", "support", "Commons", "code"]}}'::jsonb, '{"blanks": {"B1": "code"}}'::jsonb),
('computer-science:1-6-1c-software-licensing:fib:459898de', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'fib', 'fib', 1, '{"question": "A Creative _____ licence lets a creator share work under conditions such as requiring attribution.", "blankOptions": {"B1": ["licence", "Commons", "copyright", "proprietary"]}}'::jsonb, '{"blanks": {"B1": "Commons"}}'::jsonb),
('computer-science:1-6-1c-software-licensing:fib:cb24a9e2', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'fib', 'fib', 1, '{"question": "Both proprietary and open source software are still protected by _____.", "blankOptions": {"B1": ["free", "licence", "source", "copyright"]}}'::jsonb, '{"blanks": {"B1": "copyright"}}'::jsonb),
('computer-science:1-6-1c-software-licensing:match:d0407080', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Software licence”?", "options": ["Reliable, well tested, with official support and regular updates", "Costs money and cannot be customised (source code hidden)", "The legal terms setting out how you are allowed to use a piece of software", "A licence condition requiring users to credit the original creator"]}'::jsonb, '{"answer": 2, "explain": "“Software licence” means: The legal terms setting out how you are allowed to use a piece of software"}'::jsonb),
('computer-science:1-6-1c-software-licensing:match:ee317f0b', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Proprietary software”?", "options": ["The legal terms setting out how you are allowed to use a piece of software", "Released with its source code available; usually free to use, change and share", "Owned by a company, paid for, with hidden source code that cannot be changed", "May have no official support and variable quality; needs skill"]}'::jsonb, '{"answer": 2, "explain": "“Proprietary software” means: Owned by a company, paid for, with hidden source code that cannot be changed"}'::jsonb),
('computer-science:1-6-1c-software-licensing:match:96d088a4', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Closed source”?", "options": ["Reliable, well tested, with official support and regular updates", "The human-readable program instructions written by the developers", "A licence letting creators share work under conditions they choose", "Another name for proprietary — the source code is not made available"]}'::jsonb, '{"answer": 3, "explain": "“Closed source” means: Another name for proprietary — the source code is not made available"}'::jsonb),
('computer-science:1-6-1c-software-licensing:match:4a735079', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Open source software”?", "options": ["Another name for proprietary — the source code is not made available", "Released with its source code available; usually free to use, change and share", "Owned by a company, paid for, with hidden source code that cannot be changed", "A licence letting creators share work under conditions they choose"]}'::jsonb, '{"answer": 1, "explain": "“Open source software” means: Released with its source code available; usually free to use, change and share"}'::jsonb),
('computer-science:1-6-1c-software-licensing:match:563f830b', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Source code”?", "options": ["May have no official support and variable quality; needs skill", "The legal terms setting out how you are allowed to use a piece of software", "The human-readable program instructions written by the developers", "A licence condition requiring users to credit the original creator"]}'::jsonb, '{"answer": 2, "explain": "“Source code” means: The human-readable program instructions written by the developers"}'::jsonb),
('computer-science:1-6-1c-software-licensing:match:bf40d53f', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Creative Commons”?", "options": ["Protects both proprietary and open source software", "Released with its source code available; usually free to use, change and share", "A licence letting creators share work under conditions they choose", "Reliable, well tested, with official support and regular updates"]}'::jsonb, '{"answer": 2, "explain": "“Creative Commons” means: A licence letting creators share work under conditions they choose"}'::jsonb),
('computer-science:1-6-1c-software-licensing:match:b0664e75', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Attribution”?", "options": ["Protects both proprietary and open source software", "A licence condition requiring users to credit the original creator", "The legal terms setting out how you are allowed to use a piece of software", "Costs money and cannot be customised (source code hidden)"]}'::jsonb, '{"answer": 1, "explain": "“Attribution” means: A licence condition requiring users to credit the original creator"}'::jsonb),
('computer-science:1-6-1c-software-licensing:match:c4839212', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Benefit of proprietary”?", "options": ["Released with its source code available; usually free to use, change and share", "The legal terms setting out how you are allowed to use a piece of software", "Usually free and can be customised; improved by a community", "Reliable, well tested, with official support and regular updates"]}'::jsonb, '{"answer": 3, "explain": "“Benefit of proprietary” means: Reliable, well tested, with official support and regular updates"}'::jsonb),
('computer-science:1-6-1c-software-licensing:match:f70a3aa8', 'computer-science', 'computer-science:1-6-1c-software-licensing', '1.6.1c Software Licensing', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Drawback of proprietary”?", "options": ["Reliable, well tested, with official support and regular updates", "Costs money and cannot be customised (source code hidden)", "A licence condition requiring users to credit the original creator", "Owned by a company, paid for, with hidden source code that cannot be changed"]}'::jsonb, '{"answer": 1, "explain": "“Drawback of proprietary” means: Costs money and cannot be customised (source code hidden)"}'::jsonb),
